import './MonthlyExpenseChart.css';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer
} from "recharts";

function MonthlyExpenseChart(){
    const monthlyData = [
        { month: "Jan", expense: 0 },
        { month: "Feb", expense: 0 },
        { month: "Mar", expense: 0 },
        { month: "Apr", expense: 0 },
        { month: "May", expense: 0 },
        { month: "Jun", expense: 0 },
        { month: "Jul", expense: 0 },
        { month: "Aug", expense: 0 },
        { month: "Sep", expense: 0 },
        { month: "Oct", expense: 0 },
        { month: "Nov", expense: 0 },
        { month: "Dec", expense: 0 }
    ];
    return (
        <ResponsiveContainer width="100%" height={300}>
            <LineChart data={monthlyData}>
                <CartesianGrid strokeDasharray="3 3" />
        
                <XAxis dataKey="month" />
        
                <YAxis />
        
                <Tooltip />
        
                <Line
                    type="monotone"
                    dataKey="expense"
                />
            </LineChart>
        </ResponsiveContainer>
    );
}
export default MonthlyExpenseChart;
